import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../etc/passwd";
        String directory = "/home/user/data/";

        try {
            File file = new File(directory + userInput).getCanonicalFile();
            if (!file.getAbsolutePath().startsWith(directory)) {
                System.out.println("Access to files outside of the specified directory is not allowed.");
                return;
            }

            FileInputStream fis = new FileInputStream(file);
            // Process the file
            System.out.println("File contents: ");
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();

        } catch (IOException e) {
            System.out.println("Error accessing file: " + e.getMessage());
        }
    }
}

